Here's a test class using MSTest's comparison assertions for boundary checking:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ResultIsInRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        var result = _calculator.GetGrade(percentage);
        Assert.AreEqual(expected, result);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_MidRange_ResultIsInRange()
    {
        var result = _calculator.NormalizeScore(45, 100);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0, 50);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Key comparison assertions used:**

| Assertion | Purpose |
|-----------|---------|
| `Assert.IsGreaterThan(lowerBound, actual)` | Verifies actual > lower bound |
| `Assert.IsLessThan(upperBound, actual)` | Verifies actual < upper bound |
| `Assert.IsInRange(actual, low, high)` | Verifies low ≤ actual ≤ high |

These produce clear failure messages like `"Expected value to be in range [0, 100], but was 105"` — far better than `Assert.IsTrue(x >= 0 && x <= 100)`.

The tests cover: valid calculations, boundary grades (89.9 vs 90.0), clamping behavior, and all `ArgumentOutOfRangeException` guard clauses.
